import{_ as e,o as t,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Capy — Parallel-Native Cloud IDE with Captain/Build Agent Architecture","description":"","frontmatter":{"title":"Capy — Parallel-Native Cloud IDE with Captain/Build Agent Architecture","status":"complete"},"headers":[],"relativePath":"research/agents/capy/index.md","filePath":"research/agents/capy/index.md"}'),r={name:"research/agents/capy/index.md"};function i(o,a,l,c,p,d){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="capy" tabindex="-1">Capy <a class="header-anchor" href="#capy" aria-label="Permalink to &quot;Capy&quot;">​</a></h1><blockquote><p>Cloud-based AI coding IDE built for parallel agent orchestration; uses a distinctive two-agent split (Captain for planning, Build for execution) to ship entire sprints concurrently.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Capy</strong> is a commercial, cloud-based IDE/platform built by <strong>Lowercase</strong> (Lowercase Labs). Named after capybaras, Capy positions itself as &quot;the IDE for the parallel age&quot; — a platform where developers orchestrate multiple autonomous coding agents from a single dashboard, executing entire sprints in parallel rather than working tasks sequentially.</p><p>Unlike terminal-first agents (Claude Code, Aider) or IDE extensions (Cursor, Copilot), Capy is a <strong>standalone cloud IDE</strong> where the agent infrastructure is the product. Every task runs in its own sandboxed Ubuntu VM, uses git worktrees for branch isolation, and can execute concurrently with up to 25 parallel &quot;jams&quot; on the Pro plan.</p><p>Capy&#39;s most distinctive architectural decision is the <strong>Captain/Build split</strong> — a two-agent architecture where planning and execution are handled by separate agents with hard-enforced capability boundaries. Captain plans but cannot write code; Build executes but cannot ask clarifying questions. This forced separation produces real specs before any code is written, reducing the wasted iterations common in single-agent systems.</p><h3 id="what-makes-capy-special" tabindex="-1">What Makes Capy Special <a class="header-anchor" href="#what-makes-capy-special" aria-label="Permalink to &quot;What Makes Capy Special&quot;">​</a></h3><ol><li><p><strong>Captain + Build Split</strong>: Two-agent architecture with hard capability boundaries — planning agent can never write code, execution agent can never ask questions mid-task.</p></li><li><p><strong>Parallel-Native Design</strong>: Built from the ground up for concurrent execution. Run 25+ coding tasks simultaneously, each in isolated environments.</p></li><li><p><strong>Task-Based Workflow</strong>: Think in tasks, not tabs. Each task groups its chat, branch, environment, and PR as a single unit.</p></li><li><p><strong>Model Agnostic</strong>: Supports Claude Opus 4.6, GPT-5.3 Codex, Gemini 3 Pro, Grok 4 Fast, Kimi K2, GLM 4.7, Qwen 3 Coder, and more.</p></li><li><p><strong>Multiplayer Collaboration</strong>: Tag teammates, resume issues, collaborative by default — designed for teams, not solo use.</p></li></ol><h2 id="terminal-bench-scores" tabindex="-1">Terminal-Bench Scores <a class="header-anchor" href="#terminal-bench-scores" aria-label="Permalink to &quot;Terminal-Bench Scores&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Model Config</th><th>Rank</th><th>Score</th></tr></thead><tbody><tr><td>Terminal-Bench 2.0</td><td>Capy + Claude Opus 4.6</td><td>#7</td><td>75.3% ±2.4</td></tr></tbody></table><h2 id="key-stats" tabindex="-1">Key Stats <a class="header-anchor" href="#key-stats" aria-label="Permalink to &quot;Key Stats&quot;">​</a></h2><ul><li><strong>Type</strong>: Closed-source, commercial SaaS platform (cloud IDE)</li><li><strong>Website</strong>: <a href="https://capy.ai" target="_blank" rel="noreferrer">capy.ai</a></li><li><strong>Company</strong>: Lowercase (Lowercase Labs)</li><li><strong>Pricing</strong>: $20/month Pro (3 seats included), custom Enterprise; free for open source</li><li><strong>Trusted by</strong>: 50,000+ engineers</li><li><strong>Security</strong>: SOC 2 Type II certified (March 2026)</li><li><strong>Execution</strong>: Sandboxed Ubuntu VMs per task, git worktrees for isolation</li><li><strong>Parallel capacity</strong>: Up to 25 concurrent jams (Pro plan)</li><li><strong>Model support</strong>: Claude Opus 4.6, GPT-5.3 Codex, Gemini 3 Pro, Grok 4 Fast, Kimi K2, GLM 4.7, Qwen 3 Coder</li><li><strong>Source code</strong>: Not publicly available (closed-source commercial product)</li></ul><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User (describes task in Capy IDE)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│            Captain Agent            │</span></span>
<span class="line"><span>│  • Reads codebase, researches       │</span></span>
<span class="line"><span>│  • Asks clarifying questions        │</span></span>
<span class="line"><span>│  • Writes exhaustive spec           │</span></span>
<span class="line"><span>│  • CANNOT write code or run cmds    │</span></span>
<span class="line"><span>└──────────────┬──────────────────────┘</span></span>
<span class="line"><span>               │ (spec handoff)</span></span>
<span class="line"><span>               ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│             Build Agent             │</span></span>
<span class="line"><span>│  • Receives spec + codebase access  │</span></span>
<span class="line"><span>│  • Full Ubuntu VM with sudo         │</span></span>
<span class="line"><span>│  • Edits files, runs tests          │</span></span>
<span class="line"><span>│  • Opens PRs on GitHub              │</span></span>
<span class="line"><span>│  • CANNOT ask questions mid-task    │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><h2 id="files-in-this-research" tabindex="-1">Files in This Research <a class="header-anchor" href="#files-in-this-research" aria-label="Permalink to &quot;Files in This Research&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Contents</th></tr></thead><tbody><tr><td><a href="./architecture.html">architecture.md</a></td><td>Captain/Build two-agent split, cloud execution, VM sandboxing</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>Three-phase handoff: user → Captain → Build, feedback mechanisms</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>Model-agnostic design, VM execution, GitHub integration</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>Spec as context handoff, codebase exploration, Build isolation</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Planning/execution split, parallel-native, task workflow, OSS policy</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Terminal-Bench 2.0 results and context</td></tr><tr><td><a href="./references.html">references.md</a></td><td>Links to capy.ai, blog posts, resources</td></tr></tbody></table><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Website: <a href="https://capy.ai" target="_blank" rel="noreferrer">https://capy.ai</a></li><li>Blog: &quot;Captain vs Build: Why We Split the AI Agent in Two&quot; (Feb 2026)</li><li>Terminal-Bench 2.0: rank #7 (Claude Opus 4.6, 75.3% ±2.4)</li></ul>`,18)])])}const g=e(r,[["render",i]]);export{u as __pageData,g as default};
